package com.example.biometricauth;

import android.content.Context;
import android.os.Build;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricManager;

public final class BiometricUtils {
    private BiometricUtils() {}

    public static boolean canAuthenticate(@NonNull Context context) {
        BiometricManager bm = BiometricManager.from(context);
        int res;
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            res = bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG
                    | BiometricManager.Authenticators.DEVICE_CREDENTIAL);
        } else {
            res = bm.canAuthenticate();
        }
        return res == BiometricManager.BIOMETRIC_SUCCESS;
    }
}

package com.example.biometricauth;

import android.os.Build;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricPrompt;

public final class BiometricPromptFactory {
    private BiometricPromptFactory() {}

    @NonNull
    public static BiometricPrompt.PromptInfo createPromptInfo(@NonNull String title,
                                                             @NonNull String subtitle,
                                                             @NonNull String description) {
        BiometricPrompt.PromptInfo.Builder builder = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setDescription(description);

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            builder.setAllowedAuthenticators(androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG
                    | androidx.biometric.BiometricManager.Authenticators.DEVICE_CREDENTIAL);
        } else {
            builder.setNegativeButtonText("Cancel");
        }
        return builder.build();
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Switch;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class LoginActivity extends AppCompatActivity {

    private EditText etUsername;
    private EditText etPassword;
    private Button btnLogin;
    private Button btnUseBiometric;
    private Switch swEnableBiometric;
    private TextView tvStatus;

    private Executor executor;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        btnLogin = findViewById(R.id.btnLogin);
        btnUseBiometric = findViewById(R.id.btnUseBiometric);
        swEnableBiometric = findViewById(R.id.swEnableBiometric);
        tvStatus = findViewById(R.id.tvStatus);

        swEnableBiometric.setChecked(Prefs.isBiometricEnabled());
        updateBiometricUi();

        swEnableBiometric.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked) {
                if (!BiometricUtils.canAuthenticate(this)) {
                    swEnableBiometric.setChecked(false);
                    Prefs.setBiometricEnabled(false);
                    tvStatus.setText("Biometric not available. Enroll fingerprint/enable lock screen.");
                    updateBiometricUi();
                    return;
                }
                Prefs.setBiometricEnabled(true);
                tvStatus.setText("Biometric login enabled.");
            } else {
                Prefs.setBiometricEnabled(false);
                tvStatus.setText("Biometric login disabled.");
            }
            updateBiometricUi();
        });

        btnLogin.setOnClickListener(v -> {
            if (validateCredentials(etUsername.getText().toString(), etPassword.getText().toString())) {
                Prefs.setLoggedIn(true);
                navigateToMain();
                finish();
            } else {
                tvStatus.setText("Invalid username or password.");
            }
        });

        executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                Prefs.setLoggedIn(true);
                navigateToMain();
                finish();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                tvStatus.setText(errString);
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                tvStatus.setText("Fingerprint not recognized.");
            }
        });

        promptInfo = BiometricPromptFactory.createPromptInfo(
                "Unlock with biometrics",
                "Use your fingerprint to unlock",
                "You can also use device credential if available"
        );

        btnUseBiometric.setOnClickListener(v -> startBiometricAuthIfAllowed());
    }

    @Override
    protected void onResume() {
        super.onResume();

        if (Prefs.isLoggedIn()) {
            navigateToMain();
            finish();
            return;
        }

        if (Prefs.isBiometricEnabled()) {
            startBiometricAuthIfAllowed();
        }
    }

    private void startBiometricAuthIfAllowed() {
        if (!Prefs.isBiometricEnabled()) {
            tvStatus.setText("Enable biometric login first.");
            return;
        }
        if (!BiometricUtils.canAuthenticate(this)) {
            tvStatus.setText("Biometric not available. Enroll fingerprint/enable lock screen.");
            return;
        }
        biometricPrompt.authenticate(promptInfo);
    }

    private void updateBiometricUi() {
        boolean enabled = Prefs.isBiometricEnabled();
        btnUseBiometric.setVisibility(enabled ? View.VISIBLE : View.GONE);
        if (enabled && !BiometricUtils.canAuthenticate(this)) {
            btnUseBiometric.setEnabled(false);
        } else {
            btnUseBiometric.setEnabled(enabled);
        }
    }

    private boolean validateCredentials(@NonNull String username, @NonNull String password) {
        if (username.trim().isEmpty() || password.trim().isEmpty()) return false;
        return true;
    }

    private void navigateToMain() {
        startActivity(new Intent(this, MainActivity.class));
    }
}

package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private TextView tvWelcome;
    private Button btnLogout;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        tvWelcome = findViewById(R.id.tvWelcome);
        btnLogout = findViewById(R.id.btnLogout);

        tvWelcome.setText("Unlocked");

        btnLogout.setOnClickListener(v -> {
            Prefs.clearAuth();
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (!Prefs.isLoggedIn()) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        }
    }
}

